settings.custom_liquid:
{% assign stock = product.variants.first.inventory_quantity %}
{% assign product_price = product.price | money_without_currency | replace: ',', '.' | plus: 0 %}
{% assign free_shipping_text = "" %}
{% if product_price > 38.99 %}
  {% assign free_shipping_text = "gratis" %}
{% endif %}
{% assign type_lower = product.type | downcase %}

<div class="vct-info-block">

  {% if stock == 0 %}

    <div class="vct-row vct-row--warning">
      <div class="vct-icon-wrap vct-icon-wrap--orange">
        <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"><circle cx="12" cy="12" r="10"/><line x1="12" y1="8" x2="12" y2="12"/><line x1="12" y1="16" x2="12.01" y2="16"/></svg>
      </div>
      <div class="vct-row-content">
        <span class="vct-row-title vct-orange">Tijdelijk niet op voorraad</span>
        <span class="vct-row-sub">Geschatte levertijd: <strong>5–7 werkdagen</strong></span>
      </div>
    </div>

  {% else %}

    <div class="vct-row vct-row--success">
      <div class="vct-icon-wrap vct-icon-wrap--green">
        <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"><polyline points="20 6 9 17 4 12"/></svg>
      </div>
      <div class="vct-row-content">
        <span class="vct-row-title vct-green">Op voorraad</span>
        <span class="vct-row-sub" id="shipping-message"></span>
      </div>
      <div id="vct-countdown-badge" style="display:none;" class="vct-countdown-badge">
        <span id="vct-timer"></span>
      </div>
    </div>

    {% if stock <= 5 %}
      <div class="vct-divider"></div>
      {% if type_lower == 'amio' and stock == 1 %}
        <div class="vct-row vct-row--amio">
          <div class="vct-icon-wrap vct-icon-wrap--yellow">
            <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"><path d="M10.29 3.86L1.82 18a2 2 0 001.71 3h16.94a2 2 0 001.71-3L13.71 3.86a2 2 0 00-3.42 0z"/><line x1="12" y1="9" x2="12" y2="13"/><line x1="12" y1="17" x2="12.01" y2="17"/></svg>
          </div>
          <div class="vct-row-content">
            <span class="vct-row-title vct-yellow">Let op: nog <strong>1 stuk</strong> op voorraad</span>
            <span class="vct-row-sub">Bij 2 of meer stuks is de levertijd <strong>5–7 dagen</strong></span>
          </div>
        </div>
      {% else %}
        <div class="vct-row">
          <div class="vct-icon-wrap vct-icon-wrap--red">
            <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"><path d="M3 9l9-7 9 7v11a2 2 0 01-2 2H5a2 2 0 01-2-2z"/><polyline points="9 22 9 12 15 12 15 22"/></svg>
          </div>
          <div class="vct-row-content">
            <span class="vct-row-title vct-red">Nog maar <strong>{{ stock }} {% if stock == 1 %}stuk{% else %}stuks{% endif %}</strong> beschikbaar</span>
            <span class="vct-row-sub">Populair artikel — op = op</span>
          </div>
        </div>
      {% endif %}
    {% endif %}

    <div class="vct-divider"></div>

    <div class="vct-row" id="vct-threshold-row">
      <div class="vct-icon-wrap vct-icon-wrap--truck">
        <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"><rect x="1" y="3" width="15" height="13" rx="1"/><path d="M16 8h4l3 4v4h-7V8z"/><circle cx="5.5" cy="18.5" r="2.5"/><circle cx="18.5" cy="18.5" r="2.5"/></svg>
      </div>
      <div class="vct-row-content" id="vct-threshold-content">
        <span class="vct-row-title" id="vct-threshold-title">Laden...</span>
        <span class="vct-row-sub" id="vct-threshold-sub"></span>
      </div>
      <div class="vct-progress-wrap" id="vct-progress-wrap" style="display:none;">
        <div class="vct-progress-bar">
          <div class="vct-progress-fill" id="vct-progress-fill"></div>
        </div>
      </div>
    </div>

  {% endif %}

</div>

<style>
  .vct-info-block {
    border: 1px solid #e8eaf0;
    border-radius: 10px;
    overflow: hidden;
    margin: 12px 0;
    background: #fff;
  }

  .vct-row {
    display: flex;
    align-items: center;
    gap: 10px;
    padding: 11px 14px;
    position: relative;
  }

  .vct-row--success { background: #f4fbf4; }
  .vct-row--warning { background: #fff8f0; }
  .vct-row--amio    { background: #fffbee; }

  .vct-divider {
    height: 1px;
    background: #f0f2f5;
    margin: 0;
  }

  .vct-icon-wrap {
    width: 28px;
    height: 28px;
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    flex-shrink: 0;
  }

  .vct-icon-wrap--green  { background: #e6f7e6; color: #00a000; }
  .vct-icon-wrap--orange { background: #fff0e0; color: #FF7E00; }
  .vct-icon-wrap--red    { background: #fdecea; color: #cc0000; }
  .vct-icon-wrap--truck  { background: #fff0e0; color: #FF7E00; }
  .vct-icon-wrap--yellow { background: #fff8e1; color: #c89000; }

  .vct-row-content {
    display: flex;
    flex-direction: column;
    gap: 1px;
    flex: 1;
    min-width: 0;
  }

  .vct-row-title {
    font-size: 13px;
    font-weight: 600;
    color: #030a22;
    line-height: 1.3;
  }

  .vct-row-sub {
    font-size: 12px;
    color: #6b7280;
    line-height: 1.3;
  }

  .vct-row-sub strong { color: #030a22; }

  .vct-green  { color: #00a000 !important; }
  .vct-orange { color: #FF7E00 !important; }
  .vct-red    { color: #cc0000 !important; }
  .vct-yellow { color: #c89000 !important; }

  .vct-countdown-badge {
    background: #fff3e0;
    border: 1px solid #ffcc80;
    border-radius: 20px;
    padding: 3px 9px;
    font-size: 12px;
    font-weight: 700;
    color: #e04000;
    white-space: nowrap;
    flex-shrink: 0;
    font-variant-numeric: tabular-nums;
  }

  .vct-progress-wrap {
    width: 70px;
    flex-shrink: 0;
  }

  .vct-progress-bar {
    height: 5px;
    background: #e8eaf0;
    border-radius: 10px;
    overflow: hidden;
  }

  .vct-progress-fill {
    height: 100%;
    background: linear-gradient(90deg, #FF7E00, #ffaa44);
    border-radius: 10px;
    transition: width 0.4s ease;
    width: 0%;
  }
</style>

<script>
(function () {
  const FREE_SHIPPING_THRESHOLD = 3900;
  const freeShippingText = "{{ free_shipping_text | strip }}";

  function getNextWeekday(date) {
    let d = new Date(date);
    d.setDate(d.getDate() + 1);
    if (d.getDay() === 0) d.setDate(d.getDate() + 1);
    return d.toLocaleDateString('nl-NL', { weekday: 'long' });
  }

  function setShippingMessage() {
    const el = document.getElementById("shipping-message");
    if (!el) return;
    const nu = new Date();
    const dag = nu.getDay();
    const uur = nu.getHours();
    let tijdTekst, dagTekst;

    if (dag >= 1 && dag <= 5 && uur < 20) {
      tijdTekst = "20:00"; dagTekst = "vandaag";
    } else if (dag >= 1 && dag <= 4 && uur >= 20) {
      tijdTekst = "23:59"; dagTekst = getNextWeekday(nu);
    } else if ((dag === 5 && uur >= 20) || dag === 6 || dag === 0) {
      tijdTekst = "23:59"; dagTekst = "maandag";
    } else {
      tijdTekst = "23:59"; dagTekst = "morgen";
    }

    const verzending = freeShippingText ? `<strong>${freeShippingText}</strong> verzonden` : "verzonden";
    el.innerHTML = `Besteld voor <strong>${tijdTekst}</strong> &rarr; ${dagTekst} ${verzending}`;
  }

  function startTimer() {
    const badge = document.getElementById("vct-countdown-badge");
    const timerEl = document.getElementById("vct-timer");
    const nu = new Date();
    const dag = nu.getDay();
    const uur = nu.getHours();
    if (!(dag >= 1 && dag <= 5 && uur < 20)) return;

    badge.style.display = "flex";
    function update() {
      const now = new Date();
      const cutoff = new Date();
      cutoff.setHours(20, 0, 0, 0);
      const diff = cutoff - now;
      if (diff <= 0) { badge.style.display = "none"; return; }
      const h = Math.floor(diff / 3600000);
      const m = Math.floor((diff % 3600000) / 60000);
      const s = Math.floor((diff % 60000) / 1000);
      timerEl.textContent =
        String(h).padStart(2,'0') + ":" +
        String(m).padStart(2,'0') + ":" +
        String(s).padStart(2,'0');
    }
    update();
    setInterval(update, 1000);
  }

  function updateThreshold() {
    fetch('/cart.js')
      .then(r => r.json())
      .then(cart => {
        const titleEl      = document.getElementById("vct-threshold-title");
        const subEl        = document.getElementById("vct-threshold-sub");
        const progressWrap = document.getElementById("vct-progress-wrap");
        const progressFill = document.getElementById("vct-progress-fill");
        const truckWrap    = document.querySelector('.vct-icon-wrap--truck');
        if (!titleEl) return;

        const cartTotal = cart.total_price;
        const missing   = FREE_SHIPPING_THRESHOLD - cartTotal;
        const pct       = Math.min(100, Math.round((cartTotal / FREE_SHIPPING_THRESHOLD) * 100));

        if (missing <= 0) {
          titleEl.innerHTML = '<span style="color:#00a000">Gratis verzending van toepassing!</span>';
          subEl.innerHTML   = "Je bestelling wordt gratis verzonden";
          progressWrap.style.display = "none";
          if (truckWrap) { truckWrap.style.background = '#e6f7e6'; truckWrap.style.color = '#00a000'; }
        } else {
          const missingFormatted = (missing / 100).toFixed(2).replace('.', ',');
          titleEl.innerHTML = `Nog <strong>${missingFormatted}</strong> voor gratis verzending`;
          subEl.innerHTML   = "Gratis verzending vanaf 39,-";
          progressWrap.style.display = "block";
          progressFill.style.width   = pct + "%";
          if (truckWrap) { truckWrap.style.background = '#fff0e0'; truckWrap.style.color = '#FF7E00'; }
        }
      });
  }

  document.addEventListener("DOMContentLoaded", function () {
    setShippingMessage();
    startTimer();
    updateThreshold();
    document.addEventListener('cart:updated', updateThreshold);
    const cartCount = document.querySelector('[data-cart-count], .cart-count, #cart-count, .cart__count');
    if (cartCount) new MutationObserver(updateThreshold).observe(cartCount, { childList: true, subtree: true, characterData: true });
  });
})();
</script>

{%- if product.barcode != blank -%}
  <script type="application/ld+json">
  {
    "@context": "http://schema.org/",
    "@type": "Product",
    "name": {{ product.title | json }},
    "gtin13": "{{ product.barcode }}",
    "description": {{ product.description | strip_html | json }}
  }
  </script>

  <div style="display:none !important;" aria-hidden="true">
    <span>Merk: {{ product.vendor }}</span>
    <span>EAN: {{ product.barcode }}</span>
    <span>SKU: {{ product.sku }}</span>
  </div>
{%- endif -%}
